for (const item of $input.all()) {

  const webhookData = $('Webhook').item.json;
  const body = webhookData.body;

  // ─── HELPERS ───────────────────────────────────────────────
  const safeGet = (val) => Array.isArray(val) ? (val[0] || '') : (val || '');
  const safeGetName = (val) => {
    if (Array.isArray(val) && val[0]?.name) return val[0].name;
    if (val?.name) return val.name;
    return '';
  };
  const safeGetEmail = (val) => {
    if (Array.isArray(val) && val[0]?.email) return val[0].email;
    if (val?.email) return val.email;
    return '';
  };

  // ─── DETECT BRANCH ─────────────────────────────────────────
  const vaSource = safeGetName(body["VA Source"]) || "Training";
  const isSTP = vaSource === "Straight-To-Placements";

  // ─── SHARED FIELDS ─────────────────────────────────────────
  const vaName            = body["Virtual Assistant"]   || "Candidate";
  const email             = body["Personal Email"]      || "N/A";
  const phone             = body["Phone Number"]        || "N/A";
  const videoLink         = body["Intro Video"]         || "#";
  const resumeLink        = body["Resume [Link]"]       || "#";
  const endorsementSummary= body["Endorsement Summary"] || "No summary provided.";
  const rate              = body["SV Base Rate"]        || "0";
  const discLink          = body["DISC [Link]"];
  const piBehLink         = body["PI - Behavioral [Link]"];
  const piCogLink         = body["PI - Cognitive [Link]"];

  // ─── BRANCH-SPECIFIC FIELDS ────────────────────────────────
  const stpRequestName    = safeGetName(body["TA STP Requests"]) || "N/A";
  const stpRole           = safeGet(body["STP Role"])            || "N/A";
  const trainingBatch     = body["Training Batch #"]             || "N/A";
  const endorserName      = safeGetName(body["VA Endorser"])     || safeGetName(body["Created By 2"]) || "N/A";

  // ─── REQUESTOR EMAIL (dynamic fallback) ────────────────────
  const requestorEmail =
    safeGetEmail(body["Created By"]) ||
    safeGetEmail(body["Created By 2"]) ||
    (isSTP ? "placements@scalevirtually.com" : "training@scalevirtually.com");

  // ─── THEME (driven by branch) ──────────────────────────────
  const accentColor  = isSTP ? "#E8833A" : "#22C55E";
  const emailTitle   = isSTP ? "STP Endorsement" : "Training Endorsement";
  const emailSummaryLabelColor = accentColor;

  // ─── SLACK MESSAGE ─────────────────────────────────────────
  const slackMessage = isSTP
    ? `Hi Placements Team, endorsing a candidate for (${stpRequestName}) who passed the HM Interview. Please see details below -\n• ${vaName}\n• Rate: $${rate}/hr.\n• ${phone} / ${email}\n\nLet us, at TA, know if you need anything else. Thanks!`
    : `Hi Placements Team, endorsing a candidate from ${vaSource} (Batch ${trainingBatch}). Please see details below -\n• ${vaName}\n• Rate: $${rate}/hr.\n• ${phone} / ${email}\n\nLet us know if you need anything else. Thanks!`;

  // ─── DYNAMIC EMAIL SUBJECT (exposed for Gmail node) ────────
  const emailSubject = isSTP
    ? `Profile Endorsement for ${stpRequestName} ${stpRole}: ${vaName}`
    : `Profile Endorsement for Training Batch ${trainingBatch}: ${vaName}`;

  // ─── CONDITIONAL LINK ROW BUILDER ──────────────────────────
  const createLinkRow = (label, url) => {
    if (!url || url === "" || url === "To follow" || url === "Pending") return "";
    return `
      <tr>
        <td class="label-col">${label}:</td>
        <td class="value-col">
          <a href="${url}" class="link-text" target="_blank">View Report &rarr;</a>
        </td>
      </tr>`;
  };

  let assessmentRows = "";
  assessmentRows += createLinkRow("DISC Profile", discLink);
  assessmentRows += createLinkRow("PI Behavioral", piBehLink);
  assessmentRows += createLinkRow("PI Cognitive", piCogLink);

  // ─── BRANCH-SPECIFIC TABLE ROWS ────────────────────────────
  const branchRows = isSTP ? `
    <tr>
      <td class="label-col">Request Ref:</td>
      <td class="value-col">${stpRequestName}</td>
    </tr>
    <tr>
      <td class="label-col">Role ID:</td>
      <td class="value-col">${stpRole}</td>
    </tr>` : `
    <tr>
      <td class="label-col">Source:</td>
      <td class="value-col">${vaSource}</td>
    </tr>
    <tr>
      <td class="label-col">Batch Number:</td>
      <td class="value-col">${trainingBatch}</td>
    </tr>
    <tr>
      <td class="label-col">Endorsed By:</td>
      <td class="value-col">${endorserName}</td>
    </tr>`;

  // ─── HTML EMAIL ────────────────────────────────────────────
  const htmlContent = `
<!DOCTYPE html>
<html>
<head>
<style>
  html, body { margin: 0; padding: 0; background-color: #f4f6f8; }
  body { font-family: Helvetica, Arial, sans-serif; color: #333333; line-height: 1.6; font-size: 14px; }
  .outer-wrapper { width: 100%; background-color: #f4f6f8; padding: 20px 0; }
  .container { max-width: 600px; margin: 0 auto; border: 1px solid #e5e7eb; border-radius: 8px; padding: 30px; background-color: #ffffff; }
  .header-title { color: ${accentColor}; font-size: 20px; font-weight: 800; text-transform: uppercase; margin-bottom: 20px; border-bottom: 2px solid ${accentColor}; padding-bottom: 10px; text-align: center; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
  td { padding: 10px 0; vertical-align: top; font-size: 14px; border-bottom: 1px solid #f0f0f0; }
  .label-col { width: 30%; font-weight: 700; color: #111827; padding-right: 10px; white-space: nowrap; }
  .value-col { width: 70%; color: #374151; }
  .link-text { color: ${accentColor}; font-weight: 600; text-decoration: none; }
  .footer { margin-top: 30px; font-size: 12px; color: #6b7280; border-top: 1px solid #e5e7eb; padding-top: 15px; }
  a { color: #2563EB; text-decoration: none; }
</style>
</head>
<body>
<table class="outer-wrapper" role="presentation" cellspacing="0" cellpadding="0">
  <tr>
    <td align="center">
      <div class="container">
        <p>Hi Team,</p>
        <p>Please find the endorsement details for <strong>${vaName}</strong> below.</p>
        <br>
        <div class="header-title">${emailTitle}</div>
        <table role="presentation">
          <tr>
            <td colspan="2" class="label-col" style="padding-bottom: 5px; color: ${emailSummaryLabelColor};">ENDORSEMENT SUMMARY:</td>
          </tr>
          <tr>
            <td colspan="2" class="value-col" style="background-color: #fafafa; padding: 15px; border-radius: 4px; font-style: italic; border: 1px solid #eee;">
              "${endorsementSummary}"
            </td>
          </tr>
          <tr><td colspan="2" style="height: 15px;"></td></tr>
          <tr>
            <td class="label-col">Candidate Name:</td>
            <td class="value-col"><strong>${vaName}</strong></td>
          </tr>
          ${branchRows}
          <tr>
            <td class="label-col">Email:</td>
            <td class="value-col">${email !== "N/A" ? `<a href="mailto:${email}">${email}</a>` : "N/A"}</td>
          </tr>
          <tr>
            <td class="label-col">Phone:</td>
            <td class="value-col">${phone}</td>
          </tr>
          <tr>
            <td class="label-col">Intro Video:</td>
            <td class="value-col"><a href="${videoLink}" class="link-text" target="_blank">Watch Video &rarr;</a></td>
          </tr>
          <tr>
            <td class="label-col">Resume:</td>
            <td class="value-col"><a href="${resumeLink}" class="link-text" target="_blank">View Resume &rarr;</a></td>
          </tr>
          ${assessmentRows}
        </table>
        <div class="footer">
          This is an automated email. For concerns, reach out to the requestor: <a href="mailto:${requestorEmail}">${requestorEmail}</a>.
        </div>
      </div>
    </td>
  </tr>
</table>
</body>
</html>`;

  // ─── OUTPUTS ───────────────────────────────────────────────
  item.json.placement_email_html = htmlContent;
  item.json.slack_message_text   = slackMessage;
  item.json.email_subject        = emailSubject;
  item.json.requestor_email      = requestorEmail;
}

return $input.all();

